@prefix cdifd: <https://cdif.org/validation/0.1/shacl#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/xasOptionalExample_001> ;
            sh:resultMessage "A description of the resource is recommended for discovery" ;
            sh:resultPath schema1:description ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:descriptionProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/meta_xasOpt_001> ;
            sh:resultMessage "The CatalogRecord node must have schema:additionalType including dcat:CatalogRecord" ;
            sh:resultPath schema1:additionalType ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:HasValueConstraintComponent ;
            sh:sourceShape cdifd:catalogRecordTypeProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/xasOptionalExample_001> ;
            sh:resultMessage "At least one creator (author/originator) is recommended" ;
            sh:resultPath schema1:creator ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:creatorProperty ] .

